// App.js
import React, { useState } from 'react';
import IndividualAnalysis from './IndividualAnalysis';
import BatchAnalysis from './BatchAnalysis';
import Dashboard from './Dashboard';
import './App.css';
import logo from './assets/images/logo.png';

function App() {
  const [customerData, setCustomerData] = useState({
    Tenure: 5,
    OrderCount: 5,
    CashbackAmount: 12000,
    DaySinceLastOrder: 7,
    HourSpendOnApp: 30,
    OrderAmountHikeFromlastYear: 15,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    SatisfactionScore: 3,
    WarehouseToHome: 10,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Single',
    Complain: 0
  });

  const [loading, setLoading] = useState(false);

  const [selectedFile, setSelectedFile] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchLoading, setBatchLoading] = useState(false);

  const [currentView, setCurrentView] = useState('individual');
  const [dashboardData, setDashboardData] = useState(null);

  const handleInputChange = (newData) => {
    setCustomerData(newData);
  };

  const handleAnalysisComplete = (results) => {
    setDashboardData({
      individualResult: results,
      timestamp: new Date().toLocaleString(),
      type: 'individual',
      customerData: { ...customerData }
    });
  };

  const handleReset = () => {
    setCustomerData({
      Tenure: 5,
      OrderCount: 5,
      CashbackAmount: 12000,
      DaySinceLastOrder: 7,
      HourSpendOnApp: 30,
      OrderAmountHikeFromlastYear: 15,
      CouponUsed: 1,
      NumberOfDeviceRegistered: 3,
      SatisfactionScore: 3,
      WarehouseToHome: 10,
      NumberOfAddress: 4,
      CityTier: 1,
      PreferredLoginDevice: 'Mobile Phone',
      PreferredPaymentMode: 'Credit Card',
      PreferedOrderCat: 'Laptop & Accessory',
      Gender: 'Male',
      MaritalStatus: 'Single',
      Complain: 0
    });
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setSelectedFile(file);
  };

  const handleBatchAnalyze = async () => {
    setBatchLoading(true);
    setTimeout(() => {
      const batchResult = {
        total_records: 1500,
        churn_count: 345,
        churn_rate: 0.23,
        download_url: '#',
        timestamp: new Date().toLocaleString()
      };
      setBatchResults(batchResult);
      setDashboardData({
        batchResult: batchResult,
        timestamp: new Date().toLocaleString(),
        type: 'batch'
      });
      setBatchLoading(false);
    }, 3000);
  };

  const navigateToDashboard = () => {
    setCurrentView('dashboard');
  };

  return (
    <div className="app">
      <div className="app-header">
        <div className="header-left">
          <div className="logo-title-container">
            <div className="app-logo">
              <img src={logo} alt="PREDICTIVE CHURNWISE ANALYTICS" className="logo-image" />
            </div>
            <div className="title-container">
              <h1 className="app-title">E-commerce ChurnGuard</h1>
            </div>
          </div>
        </div>
        <div className="header-right">
          <div className="header-stats">
            <div className="stat-item">
              <span className="stat-label">Model Accuracy</span>
              <span className="stat-value">92%</span>
            </div>
          </div>
        </div>
      </div>

      <div className="main-layout">
        <div className="sidebar">
          <nav className="sidebar-nav">
            <button 
              className={`nav-item ${currentView === 'individual' ? 'active' : ''}`}
              onClick={() => setCurrentView('individual')}
            >
              <span className="nav-icon">🔍</span>
              <span className="nav-text">Individual Analysis</span>
            </button>
            <button 
              className={`nav-item ${currentView === 'batch' ? 'active' : ''}`}
              onClick={() => setCurrentView('batch')}
            >
              <span className="nav-icon">⚡</span>
              <span className="nav-text">Batch Processing</span>
            </button>
            <button 
              className={`nav-item ${currentView === 'dashboard' ? 'active' : ''}`}
              onClick={navigateToDashboard}
            >
              <span className="nav-icon">📊</span>
              <span className="nav-text">Dashboard</span>
            </button>
          </nav>
        </div>

        <div className="content-area">
          <div className="view-title-section">
            <h2 className="view-title">
              {currentView === 'individual' ? (
                <>
                  <span className="view-icon">👤</span>
                  Individual Customer Analysis
                </>
              ) : currentView === 'batch' ? (
                <>
                  <span className="view-icon">⚡</span>
                  Batch Processing
                </>
              ) : (
                <>
                  <span className="view-icon">📊</span>
                  Analytics Dashboard
                </>
              )}
            </h2>
          </div>

          {currentView === 'individual' ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={handleInputChange}
              onReset={handleReset}
              loading={loading}
              setLoading={setLoading}
              onAnalysisComplete={handleAnalysisComplete}
            />
          ) : currentView === 'batch' ? (
            <BatchAnalysis
              onFileChange={handleFileChange}
              onAnalyze={handleBatchAnalyze}
              loading={batchLoading}
              results={batchResults}
              selectedFile={selectedFile}
            />
          ) : (
            <Dashboard dashboardData={dashboardData} />
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
